#include<bits/stdc++.h>
using namespace std;
int a[200010],in[200010];
vector<int> mp[200010];
struct edge
{
    int u,v;
}e[200010];
int fa[200010],dp[200010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
bool flag[200010];
void dfs(int x)
{
    flag[x]=1;
    for(int i:mp[x])if(!flag[i])
    {
        dfs(i);
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
        scanf("%d",&a[i]);
    }
    int k=0;
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        if(a[u]==a[v])
        {
            fa[find(u)]=find(v);
            continue;
        }
        e[++k]=(edge){u,v};
    }
    for(int i=1;i<=k;i++)
    {
        int u=find(e[i].u),v=find(e[i].v);
        if(a[u]>a[v])
        {
            swap(u,v);
        }
        mp[u].push_back(v);
    }
    dfs(find(1));
    for(int i=1;i<=k;i++)
    {
        int u=find(e[i].u),v=find(e[i].v);
        if(a[u]>a[v])
        {
            swap(u,v);
        }
        if(flag[u]&&flag[v])
        {
            in[v]++;
        }
    }
    queue<int> q;
    q.push(find(1));
    dp[find(1)]=1;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i:mp[t])
        {
            dp[i]=max(dp[i],dp[t]+1);
            in[i]--;
            if(in[i]==0)
            {
                q.push(i);
            }
        }
    }
    printf("%d",dp[find(n)]);
    return 0;
}
